  openItems(clickedItem:any){
    this.sidebarSections.forEach((section: any) => {
    section.items.forEach((item: any) => {

      if (item.id === clickedItem.id) {
        item.isOpen = !item.isOpen; // toggle
      } else {
        item.isOpen = false; // اقفل الباقي
      }

    });
  });
  }
